  number: 66,
  title: 'The Private Label Priority',
  subtitle: 'A gatekeeper marketplace systematically prioritizes its own private-label products over objectively superior third-party offerings in search rankings.',
  framework: 'dma',
  frameworkLabel: 'Digital Markets Act',
  primaryArticles: ['Art. 6(5)'],
